import{_ as n,o as h,c as i,a0 as a}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Quản lý Chất lượng","description":"","frontmatter":{"title":"Quản lý Chất lượng"},"headers":[],"relativePath":"quality-management.md","filePath":"quality-management.md"}'),c={name:"quality-management.md"};function o(g,t,l,r,u,s){return h(),i("div",null,[...t[0]||(t[0]=[a('<h1 id="quan-ly-chat-luong" tabindex="-1">Quản lý Chất lượng <a class="header-anchor" href="#quan-ly-chat-luong" aria-label="Permalink to &quot;Quản lý Chất lượng&quot;">​</a></h1><p>Mô-đun <strong>Quản lý Chất lượng</strong> trong ABNERP cung cấp bộ công cụ toàn diện để thiết lập, theo dõi và kiểm soát các tiêu chuẩn chất lượng trong toàn bộ quy trình vận hành doanh nghiệp. Mô-đun này giúp doanh nghiệp đảm bảo sản phẩm và dịch vụ đáp ứng các yêu cầu khắt khe trước khi đến tay khách hàng.</p><h2 id="phieu-kiem-tra-chat-luong" tabindex="-1">Phiếu kiểm tra chất lượng <a class="header-anchor" href="#phieu-kiem-tra-chat-luong" aria-label="Permalink to &quot;Phiếu kiểm tra chất lượng&quot;">​</a></h2><p><strong>Phiếu kiểm tra chất lượng (Quality Inspection)</strong> là công cụ trung tâm cho phép ghi nhận kết quả kiểm tra chất lượng của hàng hóa tại nhiều giai đoạn khác nhau: khi nhập kho, trước khi sản xuất, trong quá trình sản xuất và trước khi giao hàng. Mỗi phiếu kiểm tra cho phép nhập các chỉ số đo lường, so sánh với giá trị tiêu chuẩn và ghi nhận kết quả đạt/không đạt. Phiếu kiểm tra có thể được tạo thủ công hoặc tự động sinh ra từ các quy trình mua hàng, sản xuất và bán hàng.</p><h2 id="muc-tieu-chat-luong" tabindex="-1">Mục tiêu chất lượng <a class="header-anchor" href="#muc-tieu-chat-luong" aria-label="Permalink to &quot;Mục tiêu chất lượng&quot;">​</a></h2><p><strong>Mục tiêu chất lượng (Quality Goal)</strong> cho phép doanh nghiệp thiết lập các mục tiêu cụ thể về chất lượng trong một khoảng thời gian nhất định. Ví dụ: tỷ lệ sản phẩm đạt chất lượng tối thiểu 98% trong tháng, hoặc giảm tỷ lệ lỗi xuống dưới 1%. Mỗi mục tiêu có thể gắn với một quy trình, sản phẩm hoặc bộ phận cụ thể, giúp việc đánh giá hiệu quả chất lượng trở nên rõ ràng và có căn cứ.</p><h2 id="chi-so-chat-luong" tabindex="-1">Chỉ số chất lượng <a class="header-anchor" href="#chi-so-chat-luong" aria-label="Permalink to &quot;Chỉ số chất lượng&quot;">​</a></h2><p><strong>Chỉ số chất lượng (Quality Parameter)</strong> là các thước đo cụ thể được sử dụng trong phiếu kiểm tra chất lượng. Mỗi chỉ số có thể bao gồm:</p><ul><li><strong>Giá trị tiêu chuẩn</strong>: giá trị mong đợi hoặc yêu cầu tối thiểu</li><li><strong>Phạm vi cho phép</strong>: khoảng giá trị chấp nhận được (từ/tới)</li><li><strong>Đơn vị đo lường</strong>: kg, cm, %, ppm, v.v.</li><li><strong>Phương pháp kiểm tra</strong>: hướng dẫn cách đo lường chỉ số</li></ul><p>Hệ thống hỗ trợ tạo nhóm các chỉ số theo từng loại sản phẩm hoặc quy trình, cho phép tái sử dụng và đảm bảo tính nhất quán trong kiểm tra chất lượng.</p><h2 id="tinh-nang-noi-bat" tabindex="-1">Tính năng nổi bật <a class="header-anchor" href="#tinh-nang-noi-bat" aria-label="Permalink to &quot;Tính năng nổi bật&quot;">​</a></h2><ul><li><strong>Tự động tạo phiếu kiểm tra</strong>: từ quy trình mua hàng, sản xuất và bán hàng</li><li><strong>Kiểm soát lô hàng</strong>: kiểm tra chất lượng theo lô, số seri</li><li><strong>Báo cáo chất lượng</strong>: tổng hợp kết quả kiểm tra, tỷ lệ đạt/không đạt</li><li><strong>Cảnh báo</strong>: thông báo khi kết quả kiểm tra vượt ngưỡng cho phép</li><li><strong>Phân quyền kiểm tra</strong>: kiểm soát ai được tạo, phê duyệt và xem phiếu kiểm tra</li></ul><p>Mô-đun Quản lý Chất lượng tích hợp chặt chẽ với các mô-đun Mua hàng, Sản xuất, Bán hàng và Quản lý Kho, đảm bảo chất lượng được kiểm soát xuyên suốt toàn bộ vòng đời sản phẩm.</p>',13)])])}const p=n(c,[["render",o]]);export{m as __pageData,p as default};
